-- Never use SERIAL / AUTO_INCREMENT in a multi-write design.
CREATE TABLE orders (
  id          uuid PRIMARY KEY,   -- supplied by the app as UUIDv7 / ULID
  region      text NOT NULL,
  created_at  timestamptz NOT NULL DEFAULT now()
);

resource "aws_route53_health_check" "eu" {
  fqdn              = "api-eu.example.com"
  type              = "HTTPS"
  resource_path     = "/healthz"
  request_interval  = 10
  failure_threshold = 3
}

resource "aws_route53_record" "api_eu" {
  zone_id         = var.zone_id
  name            = "api.example.com"
  type            = "A"
  set_identifier  = "eu-west-1"
  health_check_id = aws_route53_health_check.eu.id

  latency_routing_policy { region = "eu-west-1" }

  alias {
    name                   = aws_lb.eu.dns_name
    zone_id                = aws_lb.eu.zone_id
    evaluate_target_health = true
  }
}

# /healthz must reflect REAL health, not just "the process is running".
@app.get("/healthz")
def healthz():
    checks = {
        "db":    can_query(db, "SELECT 1"),
        "cache": redis.ping(),
        "queue": sqs_reachable(),
    }
    if all(checks.values()):
        return jsonify(status="ok", checks=checks), 200
    return jsonify(status="degraded", checks=checks), 503

// Regulated data must stay in the user's home region. Route by their region claim,
// not by latency. CloudFront Function on viewer-request:
function handler(event) {
  var req = event.request;
  var home = req.cookies['home_region'] && req.cookies['home_region'].value;
  req.headers['x-origin'] = {
    value: home === 'eu' ? 'api-eu.example.com' : 'api-us.example.com'
  };
  return req;
}

# One global S3 endpoint that routes to the nearest bucket and fails over fast.
resource "aws_s3control_multi_region_access_point" "assets" {
  details {
    name = "assets"
    region { bucket = aws_s3_bucket.us.id }
    region { bucket = aws_s3_bucket.eu.id }
  }
}
# Backup-only use case? Plain Cross-Region Replication (CRR) is cheaper than MRAP.

provider "aws" {
  alias  = "us"
  region = "us-east-1"
}
provider "aws" {
  alias  = "eu"
  region = "eu-west-1"
}

module "app_us" {
  source      = "./modules/app-stack"
  app_version = var.app_version
  providers   = { aws = aws.us }
}

module "app_eu" {
  source      = "./modules/app-stack"
  app_version = var.app_version
  providers   = { aws = aws.eu }
}
